    22→
    23→#include <ipset/ipset.h>
    24→#include <ctype.h>
    25→
    26→#include "rule.h"
    27→#include "utils.h"
    28→#include "cache.h"
    29→#include "acl.h"
    30→
    31→static struct ip_set white_list_ipv4;
    32→static struct ip_set white_list_ipv6;
    33→
    34→static struct ip_set black_list_ipv4;
    35→static struct ip_set black_list_ipv6;
    36→
    37→static struct cork_dllist black_list_rules;
    38→static struct cork_dllist white_list_rules;
    39→
    40→static int acl_mode = BLACK_LIST;
    41→
    42→static struct cache *block_list;
    43→
    44→static struct ip_set outbound_block_list_ipv4;
    45→static struct ip_set outbound_block_list_ipv6;
    46→static struct cork_dllist outbound_block_list_rules;
    47→
    48→#ifdef __linux__
    49→
    50→#include <unistd.h>
    51→#include <stdio.h>
    52→
    53→#define NO_FIREWALL_MODE 0
    54→#define IPTABLES_MODE    1
    55→#define FIREWALLD_MODE   2
    56→
    57→static FILE *shell_stdin;
    58→static int mode = NO_FIREWALL_MODE;
    59→
    60→static char chain_name[64];
    61→static char *iptables_init_chain =
    62→    "iptables -N %s; iptables -F %s; iptables -A OUTPUT -p tcp --tcp-flags RST RST -j %s";
    63→static char *iptables_remove_chain =
    64→    "iptables -D OUTPUT -p tcp --tcp-flags RST RST -j %s; iptables -F %s; iptables -X %s";
    65→static char *iptables_add_rule    = "iptables -A %s -d %s -j DROP";
    66→static char *iptables_remove_rule = "iptables -D %s -d %s -j DROP";
    67→
    68→static char *ip6tables_init_chain =
    69→    "ip6tables -N %s; ip6tables -F %s; ip6tables -A OUTPUT -p tcp --tcp-flags RST RST -j %s";
    70→static char *ip6tables_remove_chain =
    71→    "ip6tables -D OUTPUT -p tcp --tcp-flags RST RST -j %s; ip6tables -F %s; ip6tables -X %s";
    72→static char *ip6tables_add_rule    = "ip6tables -A %s -d %s -j DROP";
    73→static char *ip6tables_remove_rule = "ip6tables -D %s -d %s -j DROP";
    74→
    75→static char *firewalld_init_chain =
    76→    "firewall-cmd --direct --add-chain ipv4 filter %s; \
    77→     firewall-cmd --direct --passthrough ipv4 -F %s; \
    78→     firewall-cmd --direct --passthrough ipv4 -A OUTPUT -p tcp --tcp-flags RST RST -j %s";
    79→static char *firewalld_remove_chain =
    80→    "firewall-cmd --direct --passthrough ipv4 -D OUTPUT -p tcp --tcp-flags RST RST -j %s; \
    81→     firewall-cmd --direct --passthrough ipv4 -F %s; \
    82→     firewall-cmd --direct --remove-chain ipv4 filter %s";
    83→static char *firewalld_add_rule    = "firewall-cmd --direct --passthrough ipv4 -A %s -d %s -j DROP";
    84→static char *firewalld_remove_rule = "firewall-cmd --direct --passthrough ipv4 -D %s -d %s -j DROP";
    85→
    86→static char *firewalld6_init_chain =
    87→    "firewall-cmd --direct --add-chain ipv6 filter %s; \
    88→     firewall-cmd --direct --passthrough ipv6 -F %s; \
    89→     firewall-cmd --direct --passthrough ipv6 -A OUTPUT -p tcp --tcp-flags RST RST -j %s";
    90→static char *firewalld6_remove_chain =
    91→    "firewall-cmd --direct --passthrough ipv6 -D OUTPUT -p tcp --tcp-flags RST RST -j %s; \
    92→     firewall-cmd --direct --passthrough ipv6 -F %s; \
    93→     firewall-cmd --direct --remove-chain ipv6 filter %s";
    94→static char *firewalld6_add_rule    = "firewall-cmd --direct --passthrough ipv6 -A %s -d %s -j DROP";
    95→static char *firewalld6_remove_rule = "firewall-cmd --direct --passthrough ipv6 -D %s -d %s -j DROP";
    96→
    97→static int
    98→run_cmd(const char *cmd)
    99→{
   100→    int ret = 0;
   101→    char cmdstring[256];
   102→
   103→    sprintf(cmdstring, "%s\n", cmd);
   104→    size_t len = strlen(cmdstring);
   105→
   106→    if (shell_stdin != NULL) {
   107→        ret = fwrite(cmdstring, 1, len, shell_stdin);
   108→        fflush(shell_stdin);
   109→    }
   110→
   111→    return ret == len;
   112→}
   113→
   114→static int
   115→init_firewall()
   116→{
   117→    int ret = 0;
   118→    char cli[256];
   119→    FILE *fp;
   120→
   121→    if (getuid() != 0)
   122→        return -1;
   123→
   124→    sprintf(cli, "firewall-cmd --version 2>&1");
   125→    fp = popen(cli, "r");
   126→
   127→    if (fp == NULL)
   128→        return -1;
   129→
   130→    if (pclose(fp) == 0) {
   131→        mode = FIREWALLD_MODE;
   132→    } else {
   133→        /* Check whether we have permission to operate iptables.
   134→	 * Note that checking `iptables --version` is insufficient:
   135→         * eg, running within a child user namespace.
   136→	 */
   137→        sprintf(cli, "iptables -L 2>&1");
   138→        fp = popen(cli, "r");
   139→        if (fp == NULL)
   140→            return -1;
   141→        if (pclose(fp) == 0)
   142→            mode = IPTABLES_MODE;
   143→    }
   144→
   145→    sprintf(chain_name, "SHADOWSOCKS_LIBEV_%d", getpid());
   146→
   147→    if (mode == FIREWALLD_MODE) {
   148→        sprintf(cli, firewalld6_init_chain, chain_name, chain_name, chain_name);
   149→        ret |= system(cli);
   150→        sprintf(cli, firewalld_init_chain, chain_name, chain_name, chain_name);
   151→        ret |= system(cli);
   152→    } else if (mode == IPTABLES_MODE) {
   153→        sprintf(cli, ip6tables_init_chain, chain_name, chain_name, chain_name);
   154→        ret |= system(cli);
   155→        sprintf(cli, iptables_init_chain, chain_name, chain_name, chain_name);
   156→        ret |= system(cli);
   157→    }
   158→
   159→    shell_stdin = popen("/bin/sh", "w");
   160→
   161→    return ret;
   162→}
   163→
   164→static int
   165→reset_firewall()
   166→{
   167→    int ret = 0;
   168→    char cli[256];
   169→
   170→    if (getuid() != 0)
   171→        return -1;
   172→
   173→    if (mode == IPTABLES_MODE) {
   174→        sprintf(cli, ip6tables_remove_chain, chain_name, chain_name, chain_name);
   175→        ret |= system(cli);
   176→        sprintf(cli, iptables_remove_chain, chain_name, chain_name, chain_name);
   177→        ret |= system(cli);
   178→    } else if (mode == FIREWALLD_MODE) {
   179→        sprintf(cli, firewalld6_remove_chain, chain_name, chain_name, chain_name);
   180→        ret |= system(cli);
   181→        sprintf(cli, firewalld_remove_chain, chain_name, chain_name, chain_name);
   182→        ret |= system(cli);
   183→    }
   184→
   185→    if (shell_stdin != NULL) {
   186→        run_cmd("exit 0");
   187→        pclose(shell_stdin);
   188→    }
   189→
   190→    return ret;
   191→}
   192→
   193→static int
   194→set_firewall_rule(char *addr, int add)
   195→{
   196→    char cli[256];
   197→    struct cork_ip ip;
   198→
   199→    if (getuid() != 0)
   200→        return -1;
   201→
   202→    if (cork_ip_init(&ip, addr))
   203→        return -1;
   204→
   205→    if (add) {
   206→        if (mode == IPTABLES_MODE)
   207→            sprintf(cli, ip.version == 4 ? iptables_add_rule : ip6tables_add_rule,
   208→                    chain_name, addr);
   209→        else if (mode == FIREWALLD_MODE)
   210→            sprintf(cli, ip.version == 4 ? firewalld_add_rule : firewalld6_add_rule,
   211→                    chain_name, addr);
   212→        return run_cmd(cli);
   213→    } else {
   214→        if (mode == IPTABLES_MODE)
   215→            sprintf(cli, ip.version == 4 ? iptables_remove_rule : ip6tables_remove_rule,
   216→                    chain_name, addr);
   217→        else if (mode == FIREWALLD_MODE)
   218→            sprintf(cli, ip.version == 4 ? firewalld_remove_rule : firewalld6_remove_rule,
   219→                    chain_name, addr);
   220→        return run_cmd(cli);
   221→    }
   222→
   223→    return 0;
   224→}
   225→
   226→static void
   227→free_firewall_rule(void *key, void *element)
   228→{
   229→    if (key == NULL)
   230→        return;
   231→    char *addr = (char *)key;
   232→    set_firewall_rule(addr, 0);
   233→    ss_free(element);
   234→}
   235→
   236→#endif
   237→
   238→void
   239→init_block_list(int firewall)
   240→{
   241→    // Initialize cache
   242→#ifdef __linux__
   243→    if (firewall)
   244→        init_firewall();
   245→    else
   246→        mode = NO_FIREWALL_MODE;
   247→    cache_create(&block_list, 256, free_firewall_rule);
   248→#else
   249→    cache_create(&block_list, 256, NULL);
   250→#endif
   251→}
   252→
   253→void
   254→free_block_list()
   255→{
   256→#ifdef __linux__
   257→    if (mode != NO_FIREWALL_MODE)
   258→        reset_firewall();
   259→#endif
   260→    cache_clear(block_list, 0); // Remove all items
   261→}
   262→
   263→int
   264→remove_from_block_list(char *addr)
   265→{
   266→    size_t addr_len = strlen(addr);
   267→    return cache_remove(block_list, addr, addr_len);
   268→}
   269→
   270→void
   271→clear_block_list()
   272→{
   273→    cache_clear(block_list, 3600); // Clear items older than 1 hour
   274→}
   275→
   276→int
   277→check_block_list(char *addr)
   278→{
   279→    size_t addr_len = strlen(addr);
   280→
   281→    if (cache_key_exist(block_list, addr, addr_len)) {
   282→        int *count = NULL;
   283→        cache_lookup(block_list, addr, addr_len, &count);
   284→
   285→        if (count != NULL && *count > MAX_TRIES)
   286→            return 1;
   287→    }
   288→
   289→    return 0;
   290→}
   291→
   292→int
   293→update_block_list(char *addr, int err_level)
   294→{
   295→    size_t addr_len = strlen(addr);
   296→
   297→    if (cache_key_exist(block_list, addr, addr_len)) {
   298→        int *count = NULL;
   299→        cache_lookup(block_list, addr, addr_len, &count);
   300→        if (count != NULL) {
   301→            if (*count > MAX_TRIES)
   302→                return 1;
   303→            (*count) += err_level;
   304→        }
   305→    } else if (err_level > 0) {
   306→        int *count = (int *)ss_malloc(sizeof(int));
   307→        *count = 1;
   308→        cache_insert(block_list, addr, addr_len, count);
   309→#ifdef __linux__
   310→        if (mode != NO_FIREWALL_MODE)
   311→            set_firewall_rule(addr, 1);
   312→#endif
   313→    }
   314→
   315→    return 0;
   316→}
   317→
   318→static void
   319→parse_addr_cidr(const char *str, char *host, int *cidr)
   320→{
   321→    int ret = -1, n = 0;
   322→    char *pch;
   323→
   324→    pch = strchr(str, '/');
   325→    while (pch != NULL) {
   326→        n++;
   327→        ret = pch - str;
   328→        pch = strchr(pch + 1, '/');
   329→    }
   330→    if (ret == -1) {
   331→        strcpy(host, str);
   332→        *cidr = -1;
   333→    } else {
   334→        memcpy(host, str, ret);
   335→        host[ret] = '\0';
   336→        *cidr     = atoi(str + ret + 1);
   337→    }
   338→}
   339→
   340→char *
   341→trimwhitespace(char *str)
   342→{
   343→    char *end;
   344→
   345→    // Trim leading space
   346→    while (isspace(*str))
   347→        str++;
   348→
   349→    if (*str == 0)   // All spaces?
   350→        return str;
   351→
   352→    // Trim trailing space
   353→    end = str + strlen(str) - 1;
   354→    while (end > str && isspace(*end))
   355→        end--;
   356→
   357→    // Write new null terminator
   358→    *(end + 1) = 0;
   359→
   360→    return str;
   361→}
   362→
   363→int
   364→init_acl(const char *path)
   365→{
   366→    // initialize ipset
   367→    ipset_init_library();
   368→
   369→    ipset_init(&white_list_ipv4);
   370→    ipset_init(&white_list_ipv6);
   371→    ipset_init(&black_list_ipv4);
   372→    ipset_init(&black_list_ipv6);
   373→    ipset_init(&outbound_block_list_ipv4);
   374→    ipset_init(&outbound_block_list_ipv6);
   375→
   376→    cork_dllist_init(&black_list_rules);
   377→    cork_dllist_init(&white_list_rules);
   378→    cork_dllist_init(&outbound_block_list_rules);
   379→
   380→    struct ip_set *list_ipv4  = &black_list_ipv4;
   381→    struct ip_set *list_ipv6  = &black_list_ipv6;
   382→    struct cork_dllist *rules = &black_list_rules;
   383→
   384→    FILE *f = fopen(path, "r");
   385→    if (f == NULL) {
   386→        LOGE("Invalid acl path.");
   387→        return -1;
   388→    }
   389→
   390→    char buf[257];
   391→    while (!feof(f))
   392→        if (fgets(buf, 256, f)) {
   393→            // Trim the newline
   394→            int len = strlen(buf);
   395→            if (len > 0 && buf[len - 1] == '\n') {
   396→                buf[len - 1] = '\0';
   397→            }
   398→
   399→            char *line = trimwhitespace(buf);
   400→
   401→            // Skip comments
   402→            if (line[0] == '#') {
   403→                continue;
   404→            }
   405→
   406→            if (strlen(line) == 0) {
   407→                continue;
   408→            }
   409→
   410→            if (strcmp(line, "[outbound_block_list]") == 0) {
   411→                list_ipv4 = &outbound_block_list_ipv4;
   412→                list_ipv6 = &outbound_block_list_ipv6;
   413→                rules     = &outbound_block_list_rules;
   414→                continue;
   415→            } else if (strcmp(line, "[black_list]") == 0
   416→                       || strcmp(line, "[bypass_list]") == 0) {
   417→                list_ipv4 = &black_list_ipv4;
   418→                list_ipv6 = &black_list_ipv6;
   419→                rules     = &black_list_rules;
   420→                continue;
   421→            } else if (strcmp(line, "[white_list]") == 0
   422→                       || strcmp(line, "[proxy_list]") == 0) {
   423→                list_ipv4 = &white_list_ipv4;
   424→                list_ipv6 = &white_list_ipv6;
   425→                rules     = &white_list_rules;
   426→                continue;
   427→            } else if (strcmp(line, "[reject_all]") == 0
   428→                       || strcmp(line, "[bypass_all]") == 0) {
